/// <summary>
/// The <c>CustExchRateAdjSimulationDP</c> class fetches records for the
/// <c>CustExchRateAdjSimulation</c> SRSS report.
/// </summary>
[
    SRSReportParameterAttribute(classstr(CustVendExchRateAdjSimulationContract))
]
public class ETG_CustExchRateAdjSimulationDP extends SRSReportDataProviderBase
{
    ETG_CustExchRateAdjSimulationTmp eTG_CustExchRateAdjSimulationTmp;


}

Method.Source:
protected TransDate getConsideredDate()
{
    CustVendExchRateAdjSimulationContract contract = this.parmDataContract() as CustVendExchRateAdjSimulationContract;

    return contract.parmConsideredDate();
}

/// <summary>
/// Gets the data from the <c>CustExchRateAdjSimulationTmp</c> temporary table for SRS report.
/// </summary>
/// <returns>
/// The <c>CustExchRateAdjSimulationTmp</c> temporary table.
/// </returns>
[
    SRSReportDataSetAttribute(tablestr(ETG_CustExchRateAdjSimulation))
, Microsoft.Dynamics.BusinessPlatform.SharedTypes.InternalUseOnlyAttribute]
public ETG_CustExchRateAdjSimulationTmp getCustExchRateAdjSimulationTmp()
{
    select eTG_CustExchRateAdjSimulationTmp;
    return eTG_CustExchRateAdjSimulationTmp;
}

protected TransDate getExchangeRateDate()
{
    CustVendExchRateAdjSimulationContract contract = this.parmDataContract() as CustVendExchRateAdjSimulationContract;

    return contract.parmDateOfRate();
}

protected CustVendExchPrinciples getRevaluationMethod()
{
    CustVendExchRateAdjSimulationContract contract = this.parmDataContract() as CustVendExchRateAdjSimulationContract;

    return contract.parmExchPrinciple();
}

/// <summary>
/// Retrieves records based on the parameters entered.
/// </summary>
public void processReport()
{
    ETG_CustExchRateAdjSimulation eTG_CustExchRateAdjSimulation;
    CustTrans custTrans;
    CustSettlement custSettlement;
    super();
    while select eTG_CustExchRateAdjSimulation where 
        eTG_CustExchRateAdjSimulation.ETG_ConsiderDate == this.getConsideredDate()
        && eTG_CustExchRateAdjSimulation.ETG_DateOfRate == this.getExchangeRateDate()
        && eTG_CustExchRateAdjSimulation.ETG_CustVendExchPrinciples == this.getRevaluationMethod()
        {
            eTG_CustExchRateAdjSimulationTmp.ETG_ConsiderDate = eTG_CustExchRateAdjSimulation.ETG_ConsiderDate;
        eTG_CustExchRateAdjSimulationTmp.ETG_DateOfRate             = eTG_CustExchRateAdjSimulation.ETG_DateOfRate;
        eTG_CustExchRateAdjSimulationTmp.ETG_CustVendExchPrinciples = eTG_CustExchRateAdjSimulation.ETG_CustVendExchPrinciples;
        eTG_CustExchRateAdjSimulationTmp.AccountNum                 = eTG_CustExchRateAdjSimulation.AccountNum ;
        eTG_CustExchRateAdjSimulationTmp.AccountName                = eTG_CustExchRateAdjSimulation.AccountName;
        eTG_CustExchRateAdjSimulationTmp.CurrencyCode               = eTG_CustExchRateAdjSimulation.CurrencyCode;
        eTG_CustExchRateAdjSimulationTmp.TransDate                  = eTG_CustExchRateAdjSimulation.TransDate;
        eTG_CustExchRateAdjSimulationTmp.AmountCur                  = eTG_CustExchRateAdjSimulation.AmountCur;
        eTG_CustExchRateAdjSimulationTmp.CurBalance                 = eTG_CustExchRateAdjSimulation.CurBalance;
        eTG_CustExchRateAdjSimulationTmp.NewBalance                 = eTG_CustExchRateAdjSimulation.NewBalance;
        eTG_CustExchRateAdjSimulationTmp.ExchangeAdj                = eTG_CustExchRateAdjSimulation.ExchangeAdj;
        eTG_CustExchRateAdjSimulationTmp.ExchangeRate               = eTG_CustExchRateAdjSimulation.ExchangeRate;
        eTG_CustExchRateAdjSimulationTmp.CurrentBalanceReporting    = eTG_CustExchRateAdjSimulation.CurrentBalanceReporting;
        eTG_CustExchRateAdjSimulationTmp.NewBalanceReporting        = eTG_CustExchRateAdjSimulation.NewBalanceReporting;
        eTG_CustExchRateAdjSimulationTmp.ExchangeAdjReporting       = eTG_CustExchRateAdjSimulation.ExchangeAdjReporting;
        eTG_CustExchRateAdjSimulationTmp.ExchangeRateReporting      = eTG_CustExchRateAdjSimulation.ExchangeRateReporting;
        eTG_CustExchRateAdjSimulationTmp.ETGFinalSimulation         = eTG_CustExchRateAdjSimulation.ETGFinalSimulation;
        eTG_CustExchRateAdjSimulationTmp.ETG_Voucher                = eTG_CustExchRateAdjSimulation.Voucher;

        select custTrans where custTrans.LastSettleVoucher == eTG_CustExchRateAdjSimulation.Voucher &&
                               custTrans.Closed == eTG_CustExchRateAdjSimulation.ETG_DateOfRate &&
                               custTrans.TransDate == eTG_CustExchRateAdjSimulation.ETG_DateOfRate;

        eTG_CustExchRateAdjSimulationTmp.ETG_Settiledvoucher = custTrans.Voucher;
        eTG_CustExchRateAdjSimulationTmp.Settileddate        = custTrans.Closed;

        eTG_CustExchRateAdjSimulationTmp.PostingType                = eTG_CustExchRateAdjSimulation.PostingType;
        eTG_CustExchRateAdjSimulationTmp.DocumentNumber             = eTG_CustExchRateAdjSimulation.DocumentNumber;
        eTG_CustExchRateAdjSimulationTmp.DocumentDate               = eTG_CustExchRateAdjSimulation.DocumentDate;
        eTG_CustExchRateAdjSimulationTmp.InvoiceNumber              = eTG_CustExchRateAdjSimulation.InvoiceNumber;
        eTG_CustExchRateAdjSimulationTmp.LedgerAccount              = eTG_CustExchRateAdjSimulation.LedgerAccount;
        eTG_CustExchRateAdjSimulationTmp.Text                       = eTG_CustExchRateAdjSimulation.Text;
        eTG_CustExchRateAdjSimulationTmp.PostingProfile             = eTG_CustExchRateAdjSimulation.PostingProfile;
        eTG_CustExchRateAdjSimulationTmp.ETGItemFinancialdimension  = eTG_CustExchRateAdjSimulation.ETGItemFinancialdimension;
            eTG_CustExchRateAdjSimulationTmp.insert();
        }
}
